  }
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  if (typeof value === "object") {
    const candidate =
      value.amount ??
      value.value ??
      value.total ??
      value.taxable_amount ??
      value.tax ??
      value.raw ??
      null;
    if (candidate !== null) {
      return toNumber(candidate);
    }
    return null;
  }

  const cleaned = String(value)
    .replace(/,/g, "")
    .replace(/[\u20B9]/g, "")
    .replace(/\s+/g, "")
    .replace(/\/-$/g, "")
