  if (!cleaned) return null;
  const num = Number(cleaned);
  return Number.isNaN(num) ? null : num;
}

function sanitizeText(value) {
  if (value === null || value === undefined || value === "") return null;
  if (typeof value === "string") {
    const s = value.trim();
    return s === "" ? null : s;
  }
  if (typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  try {
    const serialized = JSON.stringify(value);
    if (serialized && serialized !== "{}" && serialized !== "[]") {
      return serialized;
    }
  } catch {}
  const fallback = String(value).trim();
  if (!fallback || fallback === "[object Object]") return null;
  return fallback;
}

function extractQuantity(value, rawValue = null) {
  const source = rawValue ?? value;
  if (source === null || source === undefined || source === "") return null;

  const str = String(source).replace(/,/g, "").trim();
  const m = str.match(/([-+]?\d+(?:\.\d+)?)/);
  if (!m) return null;

  const num = Number(m[1]);
  return Number.isNaN(num) ? null : num;
}

function extractUnit(value) {
  if (value === null || value === undefined || value === "") return null;
  const str = String(value).trim();
  if (!str) return null;

  const qtyUnit = str.match(/[-+]?\d[\d,]*(?:\.\d+)?\s*([A-Za-z][A-Za-z0-9 ._\/-]{0,20})$/);
  if (qtyUnit && qtyUnit[1]) return sanitizeText(qtyUnit[1]);

  const rateUnit = str.match(/\/\s*([A-Za-z][A-Za-z0-9 ._\/-]{0,20})$/);
  if (rateUnit && rateUnit[1]) return sanitizeText(rateUnit[1]);

  const perUnit = str.match(/(?:^|\bper\b)\s*([A-Za-z][A-Za-z0-9 ._\/-]{0,20})$/i);
  if (perUnit && perUnit[1]) return sanitizeText(perUnit[1]);

  return null;
}

function tryParseJson(value) {
  if (typeof value !== "string") return null;
  const s = value.trim();
  if (!s) return null;
  if (!(s.startsWith("[") || s.startsWith("{"))) return null;
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
