    return [value];
  }

  const parsedJson = tryParseJson(value);
  if (parsedJson !== null) {
    return toObjectArray(parsedJson);
  }

  return [];
}

function normalizeLineItem(row, index) {
  if (!row || typeof row !== "object") return null;
  const item = row;

  const quantity_raw = sanitizeText(
    item.quantity_raw ?? item.qty_raw ?? item.quantityRaw ?? item.qtyRaw ?? item.quantity ?? item.qty ?? null
