    quantity_raw,
    uom: inferredUom,
    rate: toNumber(item.rate ?? item.unit_rate ?? item.unitPrice ?? null),
    taxable_amount,
    cgst_rate: toNumber(item.cgst_rate ?? item.cgstRate ?? null),
    cgst,
    sgst_rate: toNumber(item.sgst_rate ?? item.sgstRate ?? null),
    sgst,
    igst_rate: toNumber(item.igst_rate ?? item.igstRate ?? null),
    igst,
    total_amount
