  }));
}

function collectLineItemCandidates(source) {
  const candidateKeys = [
    "line_items",
    "lineItems",
    "items",
    "invoice_items",
    "invoiceLines",
    "products",
    "rows",
    "table_rows",
    "details",
    "particulars"
  ];

  const out = [];
  for (const key of candidateKeys) {
    const rows = toObjectArray(source?.[key]);
    if (rows.length) out.push(...rows);
  }
  return out;
}


function splitListValues(value, delimiter) {
  if (value === null || value === undefined || value === "") return [];

  if (Array.isArray(value)) {
    return value.filter((entry) => entry !== null && entry !== undefined && entry !== "");
  }

  if (typeof value === "number" || typeof value === "boolean") {
    return [value];
  }

  const parsed = tryParseJson(value);
  if (Array.isArray(parsed)) {
    return parsed.filter((entry) => entry !== null && entry !== undefined && entry !== "");
  }

  if (typeof value !== "string") return [value];

  const str = value.trim();
  if (!str) return [];
  if (!str.includes(delimiter)) return [value];

  const parts = str
    .split(delimiter)
    .map((part) => part.trim())
    .filter((part) => part !== "");

  return parts.length > 1 ? parts : [value];
}

function detectAggregatePattern(row) {
  if (!row || typeof row !== "object") {
    return { count: 0, delimiter: null, support: 0 };
  }

  const descriptionValue =
    row.description ?? row.item_description ?? row.item ?? row.product_name ?? row.particulars ?? null;
  const hsnValue = row.hsn ?? row.hsn_sac ?? row.hsn_code ?? row.hsnCode ?? null;

  const sources = [
    descriptionValue,
    hsnValue,
    row.quantity_raw,
    row.qty_raw,
    row.quantity,
    row.rate,
    row.taxable_amount,
    row.total_amount
  ];

  const delimiters = ["\n", "|", ";", ","];
  let best = { count: 0, delimiter: null, support: 0 };

  for (const delimiter of delimiters) {
    const counts = [];

    for (const source of sources) {
      if (source === null || source === undefined) continue;
      if (typeof source === "number" || typeof source === "boolean") continue;
      const text = String(source).trim();
      if (!text || !text.includes(delimiter)) continue;

      if (delimiter === ",") {
        const numericLike = /^[-+]?\d[\d,\.\s]*$/.test(text);
        if (numericLike) continue;
      }

      const parts = splitListValues(text, delimiter);
      if (parts.length >= 2) counts.push(parts.length);
    }

    if (!counts.length) continue;

    const freq = new Map();
    for (const count of counts) freq.set(count, (freq.get(count) ?? 0) + 1);

    for (const [count, support] of freq.entries()) {
      if (count < 2) continue;
      const stronger =
        support > best.support ||
        (support === best.support && count > best.count) ||
        (support === best.support && count === best.count && delimiter !== "," && best.delimiter === ",");

      if (stronger) {
        best = { count, delimiter, support };
      }
    }
  }

  return best;
}

function hasAggregatedColumns(row) {
  const aggregate = detectAggregatePattern(row);
  return aggregate.count >= 2 && aggregate.support >= 2;
}

function maybeExpandAggregatedLineItem(row) {
  if (!row || typeof row !== "object") return [];

  const aggregate = detectAggregatePattern(row);
  if (aggregate.count < 2 || aggregate.support < 2 || !aggregate.delimiter) {
    return [row];
  }

  const expanded = [];
  for (let i = 0; i < aggregate.count; i += 1) {
    const next = {};
    for (const [key, value] of Object.entries(row)) {
      const values = splitListValues(value, aggregate.delimiter);
      if (values.length === aggregate.count) {
        next[key] = values[i] ?? null;
      } else {
        next[key] = value;
      }
    }

    if (next.line_no === null || next.line_no === undefined || next.line_no === "") {
      next.line_no = i + 1;
    }

    expanded.push(next);
  }

  return expanded.length ? expanded : [row];
}

function summarizeTax(lineItems) {
  const buckets = new Map();

  for (const line of lineItems) {
    const key = JSON.stringify({
      hsn: line.hsn ?? "",
      cgst_rate: line.cgst_rate ?? 0,
      sgst_rate: line.sgst_rate ?? 0,
      igst_rate: line.igst_rate ?? 0
    });

    if (!buckets.has(key)) {
      buckets.set(key, {
        hsn: line.hsn ?? null,
        taxable_amount: 0,
        cgst_rate: line.cgst_rate ?? null,
        cgst: 0,
        sgst_rate: line.sgst_rate ?? null,
        sgst: 0,
        igst_rate: line.igst_rate ?? null,
        igst: 0
      });
    }

    const row = buckets.get(key);
    row.taxable_amount += line.taxable_amount ?? 0;
    row.cgst += line.cgst ?? 0;
    row.sgst += line.sgst ?? 0;
    row.igst += line.igst ?? 0;
  }

  return Array.from(buckets.values()).map((row) => ({
    ...row,
    taxable_amount: Number(row.taxable_amount.toFixed(2)),
    cgst: Number(row.cgst.toFixed(2)),
    sgst: Number(row.sgst.toFixed(2)),
    igst: Number(row.igst.toFixed(2))
  }));
}

const rawLineItemCandidates = collectLineItemCandidates(parsed);
const expandedRawLineItemCandidates = rawLineItemCandidates.flatMap((row) => maybeExpandAggregatedLineItem(row));

const parsedLineItems = dedupeLineItems(
  expandedRawLineItemCandidates
    .map((row, index) => normalizeLineItem(row, index))
    .filter((row) => row !== null)
