const fallbackLineItemCandidates = maybeExpandAggregatedLineItem({
  line_no: 1,
  description: parsed.description,
  hsn: parsed.hsn,
  quantity: parsed.quantity,
  quantity_raw: parsed.quantity_raw,
  uom: parsed.uom ?? parsed.unit,
  rate: parsed.rate,
  taxable_amount: parsed.taxable_amount,
  cgst: null,
  sgst: null,
  igst: null,
  total_amount: parsed.line_total ?? parsed.total_amount
});

const fallbackLineItems = dedupeLineItems(
  fallbackLineItemCandidates
    .map((row, index) => normalizeLineItem(row, index))
    .filter((row) => row !== null)
);

const line_items = parsedLineItems.length ? parsedLineItems : fallbackLineItems;

const taxable_from_items = line_items.reduce((sum, row) => sum + (row.taxable_amount ?? 0), 0);
const cgst_from_items = line_items.reduce((sum, row) => sum + (row.cgst ?? 0), 0);
const sgst_from_items = line_items.reduce((sum, row) => sum + (row.sgst ?? 0), 0);
const igst_from_items = line_items.reduce((sum, row) => sum + (row.igst ?? 0), 0);
const total_from_items = line_items.reduce((sum, row) => sum + (row.total_amount ?? row.taxable_amount ?? 0), 0);

const taxable_amount =
  toNumber(parsed.taxable_amount ?? parsed.subtotal_taxable ?? parsed.taxableValue) ??
  (line_items.length ? Number(taxable_from_items.toFixed(2)) : null);

const hsn_tax_summary = toObjectArray(
  parsed.hsn_tax_summary ??
  parsed.hsnTaxSummary ??
  parsed.tax_summary ??
  parsed.taxSummary ??
  parsed.hsn_summary ??
  parsed.hsnSummary
)
  .map((row) => normalizeLineItem(row, 0))
  .filter((row) => row !== null)
  .map((row) => ({
    hsn: row.hsn,
    taxable_amount: row.taxable_amount,
    cgst_rate: row.cgst_rate,
    cgst: row.cgst,
    sgst_rate: row.sgst_rate,
    sgst: row.sgst,
    igst_rate: row.igst_rate,
    igst: row.igst
  }));

const TAX_EPSILON = 0.01;
const roundTax = (value) => {
  if (value === null || value === undefined) return null;
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return Number(n.toFixed(2));
};
const absTax = (value) => Math.abs(Number(value ?? 0));
const hasTax = (value) => absTax(value) > TAX_EPSILON;
const almostEqual = (a, b, tolerance = TAX_EPSILON) => absTax((a ?? 0) - (b ?? 0)) <= tolerance;

const detectTaxMode = (tuple) => {
  const c = absTax(tuple?.cgst);
  const s = absTax(tuple?.sgst);
  const i = absTax(tuple?.igst);
  const hasC = c > TAX_EPSILON;
  const hasS = s > TAX_EPSILON;
  const hasI = i > TAX_EPSILON;

  if (hasI && !hasC && !hasS) return "IGST";
  if (!hasI && (hasC || hasS)) return "CGST_SGST";
  if (!hasI && !hasC && !hasS) return "NONE";
  return "MIXED";
};

const scoreTaxTuple = (tuple) => {
  const mode = detectTaxMode(tuple);
  if (mode === "MIXED") return 0;

  let score = mode === "NONE" ? 1 : 3;
  if (mode === "CGST_SGST") {
    const c = absTax(tuple?.cgst);
    const s = absTax(tuple?.sgst);
    const tolerance = Math.max(0.5, 0.01 * Math.max(c, s));
    if (almostEqual(c, s, tolerance)) score += 1;
  }
  return score;
};

const taxMagnitude = (tuple) => absTax(tuple?.cgst) + absTax(tuple?.sgst) + absTax(tuple?.igst);
const sumTaxRows = (rows) => {
  const list = Array.isArray(rows) ? rows : [];
  const sums = list.reduce(
    (acc, row) => {
      acc.cgst += toNumber(row?.cgst) ?? 0;
      acc.sgst += toNumber(row?.sgst) ?? 0;
      acc.igst += toNumber(row?.igst) ?? 0;
      return acc;
    },
    { cgst: 0, sgst: 0, igst: 0 }
  );

  return {
    cgst: roundTax(sums.cgst),
    sgst: roundTax(sums.sgst),
    igst: roundTax(sums.igst)
  };
};

const headerTax = {
  cgst: toNumber(parsed.cgst ?? parsed.total_cgst ?? parsed.cgst_amount),
  sgst: toNumber(parsed.sgst ?? parsed.total_sgst ?? parsed.sgst_amount),
  igst: toNumber(parsed.igst ?? parsed.total_igst ?? parsed.igst_amount)
};

const lineTax = {
  cgst: line_items.length ? roundTax(cgst_from_items) : null,
  sgst: line_items.length ? roundTax(sgst_from_items) : null,
  igst: line_items.length ? roundTax(igst_from_items) : null
};

const hsnTax = sumTaxRows(hsn_tax_summary);

const sourcePriority = { line: 3, hsn: 2, header: 1 };
const rankedTaxSources = [
  { name: "line", tuple: lineTax },
  { name: "hsn", tuple: hsnTax },
  { name: "header", tuple: headerTax }
]
  .map((entry) => ({
    ...entry,
    score: scoreTaxTuple(entry.tuple),
    magnitude: taxMagnitude(entry.tuple),
    mode: detectTaxMode(entry.tuple)
  }))
  .sort((a, b) => {
    if (b.score !== a.score) return b.score - a.score;
    if (b.magnitude !== a.magnitude) return b.magnitude - a.magnitude;
    return (sourcePriority[b.name] ?? 0) - (sourcePriority[a.name] ?? 0);
  });

const preferredTax = rankedTaxSources[0]?.tuple ?? headerTax;
const preferredTaxMode = rankedTaxSources[0]?.mode ?? detectTaxMode(preferredTax);
const headerTaxMode = detectTaxMode(headerTax);

let cgst = headerTax.cgst;
let sgst = headerTax.sgst;
let igst = headerTax.igst;

const modeMismatch =
  preferredTaxMode !== "NONE" &&
  preferredTaxMode !== "MIXED" &&
  headerTaxMode !== "NONE" &&
  headerTaxMode !== preferredTaxMode;

const shouldUsePreferredTax =
  modeMismatch ||
  ((cgst === null || !hasTax(cgst)) && hasTax(preferredTax.cgst)) ||
