invoice_date: normalizedInvoiceDate,
state: sanitizeText(parsed.state ?? input.state),
      description: sanitizeText(parsed.description ?? firstLine?.description),
      hsn: sanitizeText(parsed.hsn ?? firstLine?.hsn),
