      uom: sanitizeText(parsed.uom ?? parsed.unit ?? firstLine?.uom ?? extractUnit(quantity_raw) ?? extractUnit(parsed.rate) ?? null),
      rate: toNumber(parsed.rate) ?? firstLine?.rate ?? null,
      taxable_amount,
