      cgst_raw: sanitizeText(parsed.cgst_raw ?? parsed.cgst),
      sgst,
      sgst_raw: sanitizeText(parsed.sgst_raw ?? parsed.sgst),
      igst,
      igst_raw: sanitizeText(parsed.igst_raw ?? parsed.igst),
      round_off,
      tds,
