        value.total ??
        value.taxable_amount ??
        value.tax ??
        value.raw ??
        value.rate ??
        value.quantity ??
        null;
      return candidate === null ? null : toNumber(candidate);
    }
    const cleaned = String(value)
      .replace(/[\u20B9]/g, '')
      .replace(/,/g, '')
      .replace(/\s+/g, '')
      .replace(/\/-$/g, '')
      .trim();
    if (!cleaned) return null;
    const n = Number(cleaned);
