      .filter((r) => r.hsn || r.taxable_amount !== null || r.cgst !== null || r.sgst !== null || r.igst !== null);
  }

  function sumBy(arr, key) {
    return Number((arr.reduce((s, r) => s + (toNumber(r?.[key]) ?? 0), 0)).toFixed(2));
  }

  function dedupeLedgers(names) {
    const out = [];
