  const hsnTaxSummary = normalizeHsnTaxSummary(
    approvedFromSource.hsn_tax_summary ??
      approvedFromSource.hsnTaxSummary ??
      sourceJson.hsn_tax_summary ??
      sourceJson.hsnTaxSummary ??
      []
  );

  const hasRowLevelTax = lineItems.some((li) => li.cgst !== null || li.sgst !== null || li.igst !== null);

  const invoiceDate = normalizeDateToTally(merged.invoice_date ?? merged.invoiceDate);
  const invoiceNumber = cleanText(merged.invoice_number ?? merged.invoiceNumber) || ('AUTO-' + Date.now() + '-' + idx);
  const vendorName = cleanText(merged.vendor_name ?? merged.vendorName ?? merged.party_name ?? merged.partyName) || 'Unknown Vendor';
  const purchaseLedgerName = cleanText(merged.purchase_ledger_name ?? merged.purchaseLedgerName ?? merged.tally_purchase_ledger_name) || 'Purchase';

  const headerTaxable = toNumber(merged.taxable_amount ?? merged.taxableAmount ?? merged.subtotal ?? merged.sub_total ?? merged.subTotal);
  const headerCgst = toNumber(merged.cgst ?? merged.cgst_amount ?? merged.cgstAmount);
  const headerSgst = toNumber(merged.sgst ?? merged.sgst_amount ?? merged.sgstAmount);
  const headerIgst = toNumber(merged.igst ?? merged.igst_amount ?? merged.igstAmount);
  const tds = toNumber(merged.tds ?? merged.tds_amount ?? merged.tdsAmount) ?? 0;
  const roundOff = toNumber(merged.round_off ?? merged.round_off_amount ?? merged.roundOffAmount) ?? 0;
  const headerTotal = toNumber(merged.total_amount ?? merged.totalAmount);

  const lineTaxableSum = sumBy(lineItems, 'taxable_amount');
