    cfg.approvedData?.invoice_number, cfg.approvedData?.invoiceNumber,
    cfg.body?.invoice_number, cfg.body?.invoiceNumber,
    cfg.runtimeContext?.invoiceMeta?.invoiceNumber
  );

  const rawBinaryName = pick($binary?.data?.fileName, $binary?.data?.file_name);
