const hook = $node['approval flow'].json.body ?? $node['approval flow'].json ?? {};
const response = $json?.data && typeof $json.data === 'object' ? $json.data : ($json || {});

const runtimePaths = response?.storage?.paths && typeof response.storage.paths === 'object'
  ? response.storage.paths
  : (hook.runtimeConfig?.paths || {});

const pickText = (...values) => {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const text = String(value).trim();
    if (text !== '') return text;
  }
  return '';
};

const normalizeGstin = (...values) => {
  const text = pickText(...values);
  return text ? text.toUpperCase() : null;
};

const ourGstin = normalizeGstin(
  response?.our_gstin,
  response?.ourGstin,
  response?.branch?.branchGstin,
  response?.branch?.branch_gstin,
  response?.branchGstin,
  response?.branch_gstin,
  response?.runtimeConfig?.our_gstin,
  response?.runtimeConfig?.ourGstin,
  hook?.our_gstin,
  hook?.ourGstin,
  hook?.runtimeContext?.our_gstin,
  hook?.runtimeContext?.ourGstin,
  hook?.runtimeConfig?.our_gstin,
  hook?.runtimeConfig?.ourGstin
);

const invoiceId = response.invoiceId || hook.invoiceId || hook.invoice_id || hook.id || null;
const tenantId = response.tenantId || hook.tenantId || hook.tenant_id || null;
const branchId = response.branchId || hook.branchId || hook.branch_id || null;
const originalPath = response.file?.originalFilePath || hook.originalPath || hook.originalFilePath || hook.filePath || hook.path || null;

return [{
  json: {
    ...hook,
    ...response,
    our_gstin: ourGstin,
    ourGstin,
    invoiceId,
    tenantId,
    branchId,
    originalPath,
    originalFilePath: originalPath,
    filePath: originalPath,
    path: originalPath,
    runtimeContext: {
      invoiceId,
      tenantId,
      branchId,
      our_gstin: ourGstin,
      ourGstin,
      businessStatus: response.businessStatus || null,
      file: response.file || null,
      paths: runtimePaths
    },
    runtimeConfig: {
      tenantId,
      branchId,
      our_gstin: ourGstin,
      ourGstin,
      paths: runtimePaths
    },
    incomingFolder: runtimePaths.incoming || null,
    reviewFolder: runtimePaths.review || null,
    processedFolder: runtimePaths.processed || null,
    successFolder: runtimePaths.success || null,
    exceptionFolder: runtimePaths.exception || null,
    outputFolder: runtimePaths.output || null,
    approvedData: hook.approvedData || hook.corrected_json || hook.correctedJson || response.correctedJson || null
  }
}];

