const item = $input.first();
const source = item?.json || {};
const pages = Array.isArray(source.pages) ? source.pages : [];

const mistral_text = pages
  .map((p) => (p && typeof p.markdown === 'string' ? p.markdown : ''))
  .join("\n\n");

const pickText = (...values) => {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const text = String(value).trim();
    if (text !== '') return text;
  }
  return '';
};

const normalizedGstin = pickText(
  source.our_gstin,
  source.ourGstin,
  source.runtimeConfig?.our_gstin,
  source.runtimeConfig?.ourGstin,
  source.runtimeContext?.our_gstin,
  source.runtimeContext?.ourGstin,
  source.branch?.branchGstin,
  source.branchGstin
).toUpperCase();

const ourGstin = normalizedGstin || null;

return [
  {
    json: {
